import os
import json
import sqlite3
import traceback
from datetime import datetime, timezone

from flask import Flask, Response, jsonify, render_template, send_file

import csv

app = Flask(__name__, template_folder=os.path.join(os.path.dirname(__file__), "templates"))

BASE_DIR = "/app/workspace"
DATA_DIR = os.path.join(BASE_DIR, "data")
INPUT_DIR = os.path.join(DATA_DIR, "input")
OUTPUT_JSON = os.path.join(DATA_DIR, "output.json")
DB_PATH = os.path.join(DATA_DIR, "etl.db")
LOG_PATH = os.path.join(DATA_DIR, "etl.log")


def _ts() -> str:
    return datetime.now(timezone.utc).isoformat()


def _append_log(line: str) -> None:
    os.makedirs(DATA_DIR, exist_ok=True)
    with open(LOG_PATH, "a", encoding="utf-8") as f:
        f.write(f"[{_ts()}] {line}\n")


def run_etl() -> dict:
    """Read CSVs -> write output.json -> insert into sqlite -> log."""
    os.makedirs(INPUT_DIR, exist_ok=True)
    os.makedirs(DATA_DIR, exist_ok=True)

    records = []
    for name in sorted(os.listdir(INPUT_DIR)):
        if not name.lower().endswith(".csv"):
            continue
        path = os.path.join(INPUT_DIR, name)
        with open(path, "r", encoding="utf-8", newline="") as f:
            reader = csv.DictReader(f)
            for row in reader:
                # Preserve original columns; ensure values are strings (or empty string)
                obj = {}
                for k, v in row.items():
                    obj[k] = "" if v is None else str(v)
                records.append(obj)

    # Write JSON array
    with open(OUTPUT_JSON, "w", encoding="utf-8") as out:
        json.dump(records, out)

    # Insert into DB
    conn = sqlite3.connect(DB_PATH)
    try:
        cur = conn.cursor()
        cur.execute("CREATE TABLE IF NOT EXISTS records (id INTEGER PRIMARY KEY, data TEXT)")
        for obj in records:
            cur.execute("INSERT INTO records (data) VALUES (?)", (json.dumps(obj),))
        conn.commit()
    finally:
        conn.close()

    return {"inserted": len(records)}


@app.get("/")
def index():
    return render_template("index.html")


@app.post("/trigger")
def trigger():
    try:
        result = run_etl()
        _append_log(f"SUCCESS inserted={result.get('inserted', 0)}")
        return jsonify({"status": "ok", **result})
    except Exception as e:
        _append_log(f"ERROR {type(e).__name__}: {e}")
        _append_log(traceback.format_exc().rstrip())
        return jsonify({"status": "error", "error": str(e)}), 500


@app.get("/logs")
def logs():
    os.makedirs(DATA_DIR, exist_ok=True)
    if not os.path.exists(LOG_PATH):
        return Response("", mimetype="text/plain")
    with open(LOG_PATH, "r", encoding="utf-8") as f:
        return Response(f.read(), mimetype="text/plain")


@app.get("/download")
def download():
    # Serve output.json (even if empty/nonexistent, return 404)
    return send_file(OUTPUT_JSON, mimetype="application/json", as_attachment=True, download_name="output.json")


if __name__ == "__main__":
    # Run on required host/port
    app.run(host="0.0.0.0", port=5000)
